type Row = Record<string, unknown>;
const number = (value: unknown) => Number(value || 0);
const text = (value: unknown) => typeof value === "string" ? value : undefined;
const rows = async (query: PromiseLike<{ data: unknown[] | null; error: { message: string } | null }>) => { const { data, error } = await query; if (error) throw new Error(error.message); return (data || []) as Row[]; };
async function context() { const businessId = await getActiveBusinessId(); if (!businessId) throw new Error("No authorized business workspace is selected. Complete onboarding first."); return { businessId, client: await getSupabaseServerClient() }; }
