  const { error } = await client.rpc("create_order_transactional", { p_order: payload, p_idempotency_key: input.idempotencyKey || crypto.randomUUID() }); if (error) throw new Error(`Order creation failed: ${error.message}`); return readNormalizedOperatingData();
