export async function confirmOrderImportBatchRpc(batchId: string, idempotencyKey = crypto.randomUUID()) { const { businessId, client } = await context(); const { data: auth, error: authError } = await client.auth.getUser(); if (authError || !auth.user) throw new Error("Authentication required for import confirmation."); const { data, error } = await client.rpc("confirm_order_import_batch_transactional", { p_business_id: businessId, p_batch_id: batchId, p_actor_id: auth.user.id, p_idempotency_key: idempotencyKey }); if (error) throw new Error(`Import confirmation failed: ${error.message}`); return data as Row; }
export async function getOrderImportBatchResultRpc(batchId: string) { const { businessId, client } = await context(); const [batch, rowsResult] = await Promise.all([client.from("order_import_batches").select("*").eq("business_id",businessId).eq("id",batchId).single(), client.from("order_import_rows").select("*").eq("business_id",businessId).eq("batch_id",batchId).order("row_number")]); if (batch.error) throw new Error(batch.error.message); if (rowsResult.error) throw new Error(rowsResult.error.message); return { batch: batch.data, rows: rowsResult.data || [] }; }

export async function applyParcelReceipt(parcelId: string) {
  const data = await readNormalizedOperatingData(); const parcel = data.parcels.find((entry) => entry.id === parcelId); if (!parcel) throw new Error("Parcel not found."); const po = data.purchaseOrders.find((entry) => entry.id === parcel.purchaseOrderId); const result = receiveParcelItems(parcel, po, data.balances); const { businessId, client } = await context();
  const { error: parcelError } = await client.from("inbound_parcels").update({ status: result.parcel.status, updated_at: new Date().toISOString() }).eq("id", parcel.id).eq("business_id", businessId); if (parcelError) throw new Error(parcelError.message);
  for (const item of result.parcel.items) { const { error } = await client.from("inbound_parcel_items").update({ received_quantity: item.receivedQuantity, updated_at: new Date().toISOString() }).eq("id", item.id).eq("business_id", businessId); if (error) throw new Error(error.message); }
  if (result.purchaseOrder) { const { error } = await client.from("purchase_orders").update({ status: result.purchaseOrder.status, updated_at: new Date().toISOString() }).eq("id", result.purchaseOrder.id).eq("business_id", businessId); if (error) throw new Error(error.message); for (const item of result.purchaseOrder.items) { const { error: itemError } = await client.from("purchase_order_items").update({ received_quantity: item.receivedQuantity, updated_at: new Date().toISOString() }).eq("id", item.id).eq("business_id", businessId); if (itemError) throw new Error(itemError.message); } }
  for (const balance of result.balances.filter((entry) => data.balances.some((original) => original.id === entry.id && JSON.stringify(original) !== JSON.stringify(entry)))) { const { error } = await client.from("inventory_balances").update({ on_hand: balance.onHand, incoming: balance.incoming, damaged: balance.damaged, updated_at: new Date().toISOString() }).eq("id", balance.id).eq("business_id", businessId); if (error) throw new Error(error.message); }
  const movementRows = result.movements.map((movement) => ({ business_id: businessId, variant_id: movement.variantId, quantity_delta: movement.quantity, movement_type: movement.type === "purchase_received" ? "purchase_received" : "damage", reference_type: "parcel", reference_id: parcel.id, reason: "Parcel receipt" })); if (movementRows.length) { const { error } = await client.from("stock_movements").insert(movementRows); if (error) throw new Error(error.message); }
  const { error: activityError } = await client.from("activity_events").insert({ business_id: businessId, action: "Parcel received", entity_type: "parcel", entity_id: parcel.id, detail: `${parcel.trackingNumber} was received into linked variant balances.` }); if (activityError) throw new Error(activityError.message);
  return readNormalizedOperatingData();
}
